// nodes/promptNode.js — Prompt Template node
import { BaseNode } from '../components/BaseNode';

const config = {
  title: 'Prompt Template',
  icon: '✍️',
  color: 'var(--pf-coral)',
  fields: [
    { key: 'template', label: 'Template', type: 'textarea',
      defaultValue: 'You are a helpful assistant. Answer: {{question}}',
      placeholder: 'Use {{variable}} for dynamic values' },
    { key: 'role', label: 'Role', type: 'select', defaultValue: 'user',
      options: ['user', 'system', 'assistant'] },
  ],
  inputs:  [{ id: 'context', label: 'Context' }],
  outputs: [{ id: 'prompt',  label: 'Prompt'  }],
};

export const PromptNode = (props) => <BaseNode {...props} config={config} />;
